import { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import API from "../../services/api";
import "./css/Login.css";

function Login() {
  const navigate = useNavigate();
  const [role, setRole] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  const handleLogin = async (e) => {
    e.preventDefault();
    try {
      if(!role) {
        alert("Please choose a role");
        return;
      }

      const res = await API.post("/auth/login", {
        email,
        password
      });

      // Simple navigation logic based on role selection
      if(role === "Admin") {
        navigate("/admin/dashboard");
      } else {
        navigate("/user/dashboard");
      }

    } catch (err) {
      alert("Login Failed: Incorrect email or password.");
    }
  };

  return (
    <div className="auth-page-bg bg-gradient-login">
      <div className="auth-card-modern">
        <div className="auth-header-modern">
          <h1>Welcome Back 👋</h1>
          <p>Please enter your details to sign in</p>
        </div>

        <form onSubmit={handleLogin}>

          <div className="form-group-modern">
            <label className="form-label">
              Select Role 👤
            </label>
            <select 
              className="form-input" 
              value={role} 
              onChange={(e) => setRole(e.target.value)}
              required
            >
              <option value="" disabled>Choose a role...</option>
              <option value="User">User</option>
              <option value="Admin">Admin</option>
            </select>
          </div>

          <div className="form-group-modern">
            <label className="form-label">
              Email Address 📧
            </label>
            <input
              className="form-input"
              type="email"
              required
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>

          <div className="form-group-modern">
             <label className="form-label">
              Password 🔑
              <Link to="#" className="forgot-password-link">Forgot?</Link>
            </label>
            <input
              className="form-input"
              type="password"
              required
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>

          <button className="auth-submit-btn" type="submit">
            Sign In 🚀
          </button>
        </form>

        <div className="auth-footer-text">
          Don't have an account? <Link to="/register" className="auth-footer-link" style={{color: '#8b5cf6'}}>Sign up</Link>
        </div>
      </div>

      <div className="auth-copyright">
        © 2024 SecurePortal Inc. All rights reserved. ✨
      </div>
    </div>
  );
}

export default Login;
